PUT /v2/projects/upgrade-settings HTTP/1.1
Host: api.cloud-data-services.ai
Authorization: Bearer mzoK2phr9XQw5vBme31y7e2D7FgBTiZV
Content-Type: application/json
Accept: application/json
Accept-Encoding: gzip, deflate
User-Agent: python-requests/2.31.0
Content-Length: 389

{
  "projectId": "c4f1e7b8-96bc-4c9d-9faf-ff37d9964400",
  "config": {
    "resources": [
      {"type": "db", "count": 3, "settings": {"maxConnections": 100, "timeout": 30}},
      {"type": "cache", "count": 2, "settings": {"evictionPolicy": "LRU", "ttl": 3600}}
    ],
    "scaling": {
      "autoScale": true,
      "thresholds": {
        "cpu": 75,
        "memory": 80
      },
      "alerts": ["email", "sms"]
    },
    "features": {
      "beta": false,
      "logging": {"level": "verbose", "retentionDays": 14}
    }
  }
}

